def checkAdminPassword(password):
    if len(password) < 12:
        return False
    if not any(c.isupper() for c in password):
        return False
    if not any(c.islower() for c in password):
        return False
    if not any(c.isdigit() for c in password):
        return False
    special = set('!@#$%^&*(),.?":{}|<>')
    if not any(c in special for c in password):
        return False
    weak_passwords = {'password', '123456', 'admin', 'letmein', 'qwerty', '123456789', '1234567890', 'abc123', 'password123', 'passWord12', 'Pass123456'}
    if password.lower() in weak_passwords:
        return False
    return True

